/**
 * @summary List recent messages for a chat room
 */
export const getListRoomMessagesUrl = (
  slug: string,
  params?: ListRoomMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/chat/rooms/${slug}/messages?${stringifiedParams}`
    : `/api/chat/rooms/${slug}/messages`;
};

export const listRoomMessages = async (
  slug: string,
  params?: ListRoomMessagesParams,
  options?: RequestInit,
): Promise<RoomMessagesResponse> => {
  return customFetch<RoomMessagesResponse>(
    getListRoomMessagesUrl(slug, params),
    {
      ...options,
      method: "GET",
    },
  );
};

